 6→
 7→export const ASSIGNABLE_TASK_STATUSES = ["ready", "todo"] as const;
 8→export type AssignableTaskStatus = (typeof ASSIGNABLE_TASK_STATUSES)[number];
 9→
10→// ---------------------------------------------------------------------------
11→// Orchestrator session status
12→// ---------------------------------------------------------------------------
13→
14→export const ACTIVE_ORCHESTRATOR_STATUSES = [
15→  "spawning",
16→  "active",
17→  "idle",
18→] as const;
19→export type ActiveOrchestratorStatus =
20→  (typeof ACTIVE_ORCHESTRATOR_STATUSES)[number];
21→
22→export const TERMINAL_ORCHESTRATOR_STATUSES = [
23→  "completed",
24→  "aborted",
25→  "error",
26→] as const;
27→export type TerminalOrchestratorStatus =
28→  (typeof TERMINAL_ORCHESTRATOR_STATUSES)[number];
29→
30→export type OrchestratorStatus =
31→  | ActiveOrchestratorStatus
32→  | TerminalOrchestratorStatus;
