  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
260→
261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const sessionId = request.params.sessionId;
272→
273→    if (!sessionId) {
274→      return jsonError("sessionId is required", 400);
275→    }
276→
277→    const streamId = `stream-${sessionId}`;
278→    return deps.sseRegistry.handleStreamRequest(streamId);
279→  };
280→
281→  return { stream };
282→}
283→
284→// ---------------------------------------------------------------------------
285→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
286→// ---------------------------------------------------------------------------
287→
288→export type OrchestratorWiringDeps = {
289→  surreal: import("surrealdb").Surreal;
290→  shellExec: import("./worktree-manager").ShellExec;
291→  brainBaseUrl: string;
292→  sseRegistry?: SseRegistry;
293→  queryFn: import("./spawn-agent").QueryFn;
294→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
295→};
296→
297→export function wireOrchestratorRoutes(
298→  wiringDeps: OrchestratorWiringDeps,
299→): {
300→  assign: RouteHandler;
301→  status: RouteHandler;
302→  accept: RouteHandler;
303→  abort: RouteHandler;
304→  review: RouteHandler;
305→  reject: RouteHandler;
306→  prompt: RouteHandler;
307→  stream?: RouteHandler;
308→} {
309→  // Workspace access guard — resolves user from session cookie, checks membership
310→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
311→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
312→    if (!session?.user?.id) {
313→      return jsonError("authentication required", 401);
314→    }
315→    const { RecordId } = await import("surrealdb");
316→    const personRecord = new RecordId("person", session.user.id);
317→    const workspaceRecord = new RecordId("workspace", workspaceId);
318→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
319→      `SELECT role FROM member_of WHERE in = $person AND out = $ws LIMIT 1;`,
320→      { person: personRecord, ws: workspaceRecord },
321→    );
322→    if (!memberRows || memberRows.length === 0) {
323→      return jsonError("not a member of this workspace", 403);
324→    }
325→    return undefined;
326→  };
327→
328→  // Lazy imports to keep module boundary clean
329→  const lifecycleImport = import("./session-lifecycle");
330→  const queriesImport = import("../mcp/mcp-queries");
331→  const guardImport = import("./assignment-guard");
332→  const stallDetectorImport = import("./stall-detector");
333→
334→  // Helper: resolve repo_path from workspace record
335→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
336→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
337→      `SELECT repo_path FROM $ws;`,
338→      { ws: workspaceRecord },
339→    );
340→    const repoPath = rows[0]?.repo_path;
341→    if (!repoPath) {
342→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
343→    }
344→    return repoPath;
345→  };
346→
347→  // Use mock spawn for acceptance tests, production spawn otherwise
348→  const spawnAgentImport = process.env.ORCHESTRATOR_MOCK_AGENT === "true"
349→    ? Promise.resolve({
350→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
351→          () => ({
352→            messages: (async function* () {})(),
353→            abort: () => {},
354→          }),
355→      })
356→    : import("./spawn-agent");
357→
358→  const routeDeps: OrchestratorRouteDeps = {
359→    createSession: async (workspaceId, taskId, authToken) => {
360→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
361→        lifecycleImport,
362→        queriesImport,
363→        guardImport,
364→        spawnAgentImport,
365→        stallDetectorImport,
366→      ]);
367→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
368→      const result = await lifecycle.createOrchestratorSession({
369→        surreal: wiringDeps.surreal,
370→        shellExec: wiringDeps.shellExec,
371→        brainBaseUrl: wiringDeps.brainBaseUrl,
372→        workspaceId,
373→        taskId,
374→        authToken,
375→        validateAssignment: guard.validateAssignment,
376→        createAgentSession: queries.createAgentSession,
377→        spawnAgent,
378→      });
379→
380→      // Wire SSE stream + event iteration on success
381→      if (result.ok && wiringDeps.sseRegistry) {
382→        const { agentSessionId, streamId } = result.value;
383→        wiringDeps.sseRegistry.registerMessage(streamId);
384→
385→        const handle = lifecycle.getHandle(agentSessionId);
386→        if (handle) {
387→          const { RecordId } = await import("surrealdb");
388→          lifecycle.startEventIteration(
389→            {
390→              emitEvent: wiringDeps.sseRegistry.emitEvent,
391→              updateSessionStatus: async (sid, status, error) => {
392→                const rec = new RecordId("agent_session", sid);
393→                await wiringDeps.surreal.update(rec).merge({
394→                  orchestrator_status: status,
395→                  ...(error !== undefined ? { error } : {}),
396→                });
397→              },
398→              updateLastEventAt: async (sid) => {
399→                const rec = new RecordId("agent_session", sid);
400→                await wiringDeps.surreal.update(rec).merge({
401→                  last_event_at: new Date(),
402→                });
403→              },
404→              getSessionStatus: async (sid) => {
405→                const rec = new RecordId("agent_session", sid);
406→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
407→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
408→              },
409→              startStallDetector: (sid, stId) =>
410→                stallDetector.startStallDetector(
411→                  {
412→                    abortSession: async (abortSid) => {
413→                      const abortResult = await lifecycle.abortOrchestratorSession({
414→                        surreal: wiringDeps.surreal,
415→                        shellExec: wiringDeps.shellExec,
416→                        resolveRepoRoot,
417→                        sessionId: abortSid,
418→                        endAgentSession: queries.endAgentSession,
419→                      });
420→                      return abortResult;
421→                    },
422→                    createObservation: async () => {},
423→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
424→                  },
425→                  stallDetector.DEFAULT_STALL_CONFIG,
426→                  sid,
427→                  stId,
428→                ),
429→            },
430→            handle.messages,
431→            streamId,
432→            agentSessionId,
433→          );
434→        }
435→      }
436→
437→      return result;
438→    },
439→
440→    getSessionStatus: async (sessionId) => {
441→      const lifecycle = await lifecycleImport;
442→      return lifecycle.getOrchestratorSessionStatus({
443→        surreal: wiringDeps.surreal,
444→        sessionId,
445→      });
446→    },
447→
448→    abortSession: async (sessionId) => {
449→      const [lifecycle, queries] = await Promise.all([
450→        lifecycleImport,
451→        queriesImport,
452→      ]);
453→      return lifecycle.abortOrchestratorSession({
454→        surreal: wiringDeps.surreal,
455→        shellExec: wiringDeps.shellExec,
456→        resolveRepoRoot,
457→        sessionId,
458→        endAgentSession: queries.endAgentSession,
459→      });
460→    },
461→
462→    acceptSession: async (sessionId, summary) => {
463→      const [lifecycle, queries] = await Promise.all([
464→        lifecycleImport,
465→        queriesImport,
466→      ]);
467→      return lifecycle.acceptOrchestratorSession({
468→        surreal: wiringDeps.surreal,
469→        sessionId,
470→        summary,
471→        endAgentSession: queries.endAgentSession,
472→      });
473→    },
474→
475→    getReview: async (sessionId) => {
476→      const [lifecycle, worktreeManager] = await Promise.all([
477→        lifecycleImport,
478→        import("./worktree-manager"),
479→      ]);
480→      return lifecycle.getOrchestratorReview({
481→        surreal: wiringDeps.surreal,
482→        sessionId,
483→        resolveRepoRoot,
484→        getDiff: (repoRoot: string, branchName: string) =>
485→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
486→        getTaskTitle: async (taskId: string) => {
487→          const { RecordId } = await import("surrealdb");
488→          const taskRecord = new RecordId("task", taskId);
489→          const rows = (await wiringDeps.surreal.query(
490→            `SELECT title FROM $task;`,
491→            { task: taskRecord },
492→          )) as Array<Array<{ title: string }>>;
493→          return rows[0]?.[0]?.title ?? "";
494→        },
495→      });
496→    },
497→
498→    rejectSession: async (sessionId, feedback) => {
499→      const lifecycle = await lifecycleImport;
500→      return lifecycle.rejectOrchestratorSession({
501→        surreal: wiringDeps.surreal,
502→        sessionId,
503→        feedback,
504→      });
505→    },
506→
507→    sendPrompt: async (sessionId, text) => {
508→      const lifecycle = await lifecycleImport;
509→      return lifecycle.sendSessionPrompt({
510→        surreal: wiringDeps.surreal,
511→        sessionId,
512→        text,
513→      });
514→    },
515→  };
516→
517→  const handlers = createOrchestratorRouteHandlers(routeDeps);
518→
519→  // Wrap handler with workspace access check
520→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
521→    const workspaceId = request.params.workspaceId;
522→    if (workspaceId) {
523→      const accessError = await validateWorkspaceAccess(request, workspaceId);
524→      if (accessError) return accessError;
525→    }
526→    return handler(request);
527→  };
528→
529→  const streamHandler = wiringDeps.sseRegistry
530→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
531→    : undefined;
532→
533→  return {
534→    assign: withRequestLogging("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
535→    status: withRequestLogging("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
536→    accept: withRequestLogging("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
537→    abort: withRequestLogging("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
538→    review: withRequestLogging("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
539→    reject: withRequestLogging("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
540→    prompt: withRequestLogging("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
541→    ...(streamHandler
542→      ? { stream: withRequestLogging("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
543→      : {}),
544→  };
545→}
546→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus, TerminalOrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→import { logError, logInfo, logWarn } from "../http/observability";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types — exported for tests
 16→// ---------------------------------------------------------------------------
 17→
 18→export type SessionDeps = {
 19→  surreal: Surreal;
 20→  shellExec: ShellExec;
 21→  brainBaseUrl: string;
 22→  spawnAgent?: SpawnAgentFn;
 23→};
 24→
 25→export type SessionErrorCode =
 26→  | "TASK_NOT_FOUND"
 27→  | "TASK_NOT_ASSIGNABLE"
 28→  | "AGENT_ALREADY_ACTIVE"
 29→  | "WORKSPACE_MISMATCH"
 30→  | "MISSING_TASK_ID"
 31→  | "WORKTREE_ERROR"
 32→  | "SESSION_NOT_FOUND"
 33→  | "SESSION_ERROR";
 34→
 35→export type SessionError = {
 36→  code: SessionErrorCode;
 37→  message: string;
 38→  httpStatus: number;
 39→};
 40→
 41→export type SessionResult<T> =
 42→  | { ok: true; value: T }
 43→  | { ok: false; error: SessionError };
 44→
 45→export type OrchestratorSessionResult = SessionResult<{
 46→  agentSessionId: string;
 47→  streamId: string;
 48→  worktreeBranch: string;
 49→}>;
 50→
 51→export type SessionStatusResult = SessionResult<{
 52→  orchestratorStatus: OrchestratorStatus;
 53→  worktreeBranch?: string;
 54→  worktreePath?: string;
 55→  lastEventAt?: string;
 56→  startedAt?: string;
 57→  error?: string;
 58→}>;
 59→
 60→export type AbortSessionResult = SessionResult<{
 61→  aborted: boolean;
 62→  sessionId: string;
 63→}>;
 64→
 65→export type AcceptSessionResult = SessionResult<{
 66→  accepted: boolean;
 67→  sessionId: string;
 68→}>;
 69→
 70→export type ReviewResult = SessionResult<{
 71→  taskTitle: string;
 72→  diff: import("./worktree-manager").DiffResult;
 73→  session: {
 74→    orchestratorStatus: string;
 75→    worktreeBranch?: string;
 76→    startedAt?: string;
 77→    lastEventAt?: string;
