 42→}): Promise<IntentContextResult> {
 43→  const { surreal, embeddingModel, embeddingDimension, workspaceRecord, workspaceName, intent } = input;
 44→
 45→  // Step 1: Explicit entity references in intent text
 46→  const explicitTask = extractEntityRef(intent, "task");
 47→  if (explicitTask) {
 48→    try {
 49→      const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId: explicitTask });
 50→      return { level: "task", data };
 51→    } catch {
 52→      // Task not found — fall through to other strategies
 53→    }
 54→  }
 55→
 56→  const explicitProject = extractEntityRef(intent, "project");
 57→  if (explicitProject) {
 58→    try {
 59→      const projectRecord = new RecordId("project", explicitProject);
 60→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
 61→      return { level: "project", data };
 62→    } catch {
 63→      // Project not found — fall through
 64→    }
 65→  }
 66→
 67→  // Step 2: Single-project shortcut
 68→  const projects = await listWorkspaceProjects(surreal, workspaceRecord);
 69→  if (projects.length === 1) {
 70→    const data = await buildProjectContext({
 71→      surreal,
 72→      workspaceRecord,
 73→      workspaceName,
 74→      projectRecord: projects[0].id,
 75→    });
 76→    return { level: "project", data };
 77→  }
 78→
 79→  // Step 3: Vector search — embed intent, match against all entities
 80→  const queryEmbedding = await createEmbeddingVector(embeddingModel, intent, embeddingDimension);
 81→  if (queryEmbedding) {
 82→    const results = await searchEntitiesByEmbedding({
 83→      surreal,
 84→      workspaceRecord,
 85→      queryEmbedding,
 86→      limit: 5,
 87→    });
 88→
 89→    if (results.length > 0 && results[0].score > 0.3) {
 90→      const top = results[0];
 91→
 92→      if (top.kind === "task") {
 93→        const taskId = top.id.includes(":") ? top.id.split(":")[1] : top.id;
 94→        try {
 95→          const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId });
 96→          return { level: "task", data };
 97→        } catch {
 98→          // Fall through
 99→        }
100→      }
101→
102→      // For project/feature matches, or task fallback: resolve to project context
103→      const projectRecord = await resolveProjectFromMatch(surreal, top);
104→      if (projectRecord) {
105→        const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
106→        return { level: "project", data };
107→      }
108→    }
109→  }
110→
111→  // Step 4: Path matching — match directory names against project names
112→  const allPaths = [...(input.paths ?? [])];
113→  if (input.cwd) allPaths.push(input.cwd);
114→
115→  if (allPaths.length > 0 && projects.length > 0) {
116→    const matched = matchPathToProject(allPaths, projects);
117→    if (matched) {
118→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord: matched });
119→      return { level: "project", data };
120→    }
121→  }
122→
123→  // Step 5: Fallback — workspace overview
124→  const data = await buildWorkspaceOverview({ surreal, workspaceRecord, workspaceName });
125→  return { level: "workspace", data };
126→}
