132→/** Extract explicit entity reference like `task:abc123` or `project:def456` from text */
133→function extractEntityRef(text: string, entityType: string): string | undefined {
134→  const pattern = new RegExp(`\\b${entityType}:([a-zA-Z0-9_-]+)`, "i");
135→  const match = text.match(pattern);
136→  return match ? match[1] : undefined;
137→}
